logging.basicConfig(filename='home_directory_cleaner.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def is_protected(path):
    """Check if a file or directory is protected by the system."""
    return os.access(path, os.W_OK) or os.access(path, os.X_OK)

def clean_directory(directory):
    """Recursively clean a directory and its contents."""
    for item in os.listdir(directory):
        item_path = os.path.join(directory, item)
        if is_protected(item_path):
            logging.warning(f"Skipping protected file/directory: {item_path}")
            continue
        try:
            if os.path.isfile(item_path):
                os.remove(item_path)
                logging.info(f"Deleted file: {item_path}")
            elif os.path.isdir(item_path):
                shutil.rmtree(item_path)
                logging.info(f"Deleted directory: {item_path}")
        except Exception as e:
            logging.error(f"Error cleaning {item_path}: {e}")

def main():
    user_directory = '/home/user'
    try:
        clean_directory(user_directory)
    except Exception as e:
        logging.error(f"Error cleaning {user_directory}: {e}")

if __name__ == "__main__":
    main()
